all: disk-img kernel-rv kernel-la
	@cp "$(DISK_IMG)" "$(DISK_RV_IMG)"
	@cp "$(DISK_IMG)" "$(DISK_LA_IMG)"
	@echo "[Makefile] cp $(DISK_IMG) to $(DISK_RV_IMG) and $(DISK_LA_IMG) finished"

build: all

kernel-rv:
	@$(MAKE) -C os kernel ARCH=riscv64
	@cp -f "os/target/riscv64gc-unknown-none-elf/release/os" "$(KERNEL_RV)"

kernel-la: 
	@$(MAKE) -C os kernel ARCH=loongarch64
	@cp -f "os/target/loongarch64-unknown-none/release/os" "$(KERNEL_LA)"

disk-img:
	@echo "[Makefile] building $(DISK_IMG) for online judge"
	@if [ ! -d "$(ETC_OVERLAY)" ]; then \
		echo "[Makefile] error: etc overlay not found: $(ETC_OVERLAY)"; \
		exit 1; \
	fi
	@if ! command -v mkfs.ext4 >/dev/null 2>&1; then \
		echo "[Makefile] error: mkfs.ext4 not found, cannot create $(DISK_IMG)"; \
		exit 1; \
	fi
	@echo "[Makefile] cleaning up"
	@rm -f "$(DISK_IMG)" "$(DISK_IMG_COPY)"
	@rm -rf "$(DISK_MNT)"
	@echo "[Makefile] making disk-img dir"
	@mkdir -p "$(DISK_MNT)"
	@dd if=/dev/zero of="$(DISK_IMG)" bs=1M count="$(DISK_IMG_MB)"
	@mkfs.ext4 -F -O ^metadata_csum_seed "$(DISK_IMG)"
	@mount "$(DISK_IMG)" "$(DISK_MNT)"
	@echo "[Makefile] create basic dirs"
	@mkdir -p "$(DISK_MNT)/bin" "$(DISK_MNT)/lib" "$(DISK_MNT)/lib64" "$(DISK_MNT)/usr" "$(DISK_MNT)/usr/lib64" "$(DISK_MNT)/mnt" "$(DISK_MNT)/tmp" "$(DISK_MNT)/var/tmp"
	@echo "[Makefile] copying $(ETC_OVERLAY) to $(DISK_IMG)"
	@cp -r "$(ETC_OVERLAY)" "$(DISK_MNT)/"
	@umount "$(DISK_MNT)"
	@rm -rf "$(DISK_MNT)"
	@chmod 777 "$(DISK_IMG)"
	@echo "[Makefile] building $(DISK_IMG) finished"
	@cp "$(DISK_IMG)" "$(DISK_IMG_COPY)"
	@echo "[Makefile] cp $(DISK_IMG) to $(DISK_IMG_COPY) finished"


