/// clear BSS segment
fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(sbss as usize as *mut u8, ebss as usize - sbss as usize)
            .fill(0);
    }
}

/// Allow U-mode to read cycle/time/instret counters.
fn enable_user_counters() {
    Instruction::enable_user_counters();
}

#[no_mangle]
/// the rust entry-point of os
pub fn rust_main() -> ! {
    clear_bss();
    enable_user_counters();
    Instruction::enable_floating_point();
    println!("[kernel] Hello, world!");
    logging::init();
    mm::init();
    mm::remap_test();
    trap::init();
    mm::kernel_vmap_smoke_test();
    fs::list_apps();
    mission::add_initproc();
    trap::enable_timer_interrupt();
    timer::set_next_trigger();
    mission::run_tasks();
    mm::dump_allocator_stats();
    panic!("Unreachable in rust_main!");
}

