const BLOCK_SIZE: usize = 512;

#[derive(Default)]
struct BlockIoStats {
    batched_reads: AtomicU64,
    batched_writes: AtomicU64,
    batched_blocks: AtomicU64,
}

lazy_static! {
    static ref BLOCK_IO_STATS: BlockIoStats = BlockIoStats::default();
}

pub(crate) fn note_block_batch(is_write: bool, blocks: usize) {
    if blocks <= 1 {
        return;
    }
    BLOCK_IO_STATS
        .batched_blocks
        .fetch_add(blocks as u64, Ordering::Relaxed);
    if is_write {
        BLOCK_IO_STATS
            .batched_writes
            .fetch_add(1, Ordering::Relaxed);
    } else {
        BLOCK_IO_STATS.batched_reads.fetch_add(1, Ordering::Relaxed);
    }
}

pub(crate) fn dump_block_io_stats_labeled(label: &str) {
    println!(
        "[fs-opt] {} block_batch read_ops={} write_ops={} blocks={}",
        label,
        BLOCK_IO_STATS.batched_reads.load(Ordering::Relaxed),
        BLOCK_IO_STATS.batched_writes.load(Ordering::Relaxed),
        BLOCK_IO_STATS.batched_blocks.load(Ordering::Relaxed),
    );
}

/// Trait for block devices.
pub(crate) trait BlockDevice: Send + Sync {
    /// Read one block into buffer.
    fn read_block(&self, block_id: usize, buf: &mut [u8]);
    /// Write one block from buffer.
    fn write_block(&self, block_id: usize, buf: &[u8]);
    /// Read a contiguous block range into a buffer.
    fn read_blocks(&self, block_id: usize, buf: &mut [u8]) {
        assert!(
            buf.len() % BLOCK_SIZE == 0,
            "read_blocks buffer must be block-aligned: len={}",
            buf.len()
        );
        note_block_batch(false, buf.len() / BLOCK_SIZE);
        for (idx, chunk) in buf.chunks_exact_mut(BLOCK_SIZE).enumerate() {
            self.read_block(block_id + idx, chunk);
        }
    }
    /// Write a contiguous block range from a buffer.
    fn write_blocks(&self, block_id: usize, buf: &[u8]) {
        assert!(
            buf.len() % BLOCK_SIZE == 0,
            "write_blocks buffer must be block-aligned: len={}",
            buf.len()
        );
        note_block_batch(true, buf.len() / BLOCK_SIZE);
        for (idx, chunk) in buf.chunks_exact(BLOCK_SIZE).enumerate() {
            self.write_block(block_id + idx, chunk);
        }
    }
    /// Total number of 512-byte blocks on this device.
    fn total_blocks(&self) -> usize;
}

type BlockDeviceImpl = virtio_blk::VirtIOBlock;

lazy_static! {
    /// The global block device driver instance: BLOCK_DEVICE with BlockDevice trait
    pub(crate) static ref BLOCK_DEVICE: Arc<dyn BlockDevice> = Arc::new(BlockDeviceImpl::new());
}

